#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005

int maxSumSubarray(char* charArray, int* intArray, int N) {
    int maxSum = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            int sum = 0;
            for (int k = i; k <= j; k++) {
                sum += intArray[k];
            }
            if (isBalanced(charArray, i, j) && sum > maxSum) {
                maxSum = sum;
            }
        }
    }
    return maxSum > 0 ? maxSum : 0;
}

int isBalanced(char* charArray, int start, int end) {
    int stack[MAX];
    int top = -1;
    for (int i = start; i <= end; i++) {
        if (charArray[i] == '(' || charArray[i] == '{' || charArray[i] == '[' || charArray[i] == '<') {
            stack[++top] = charArray[i];
        } else if (charArray[i] == ')' || charArray[i] == '}' || charArray[i] == ']' || charArray[i] == '>') {
            if (top == -1) return 0;
            char opening = stack[top--];
            if ((charArray[i] == ')' && opening != '(') || (charArray[i] == '}' && opening != '{') || (charArray[i] == ']' && opening != '[') || (charArray[i] == '>' && opening != '<')) {
                return 0;
            }
        }
    }
    return top == -1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char charArray[N + 1];
        scanf("%s", charArray);
        int intArray[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &intArray[i]);
        }
        printf("%d\n", maxSumSubarray(charArray, intArray, N));
    }
    return 0;
}

